INSERT INTO `questions` VALUES ('00E7EF3A-0E97-4EC0-894F-31D62DD320F0','Which SQL query selects all columns and all rows from the Sheet1 table?',1,3,0,'45D6C72F-A6A7-46C5-857C-E199CDFE978D','fda8e54c-5755-4ad4-86a1-b77698bbd5a0',1,1,'2026-04-08 13:55:26.882179',NULL),('076601D7-1A1D-4C0C-AF8C-E7C6FB7D6876','How can you write a query to select the names and grades of all students who scored at least 70, while also ensuring the results are limited to the top 2 entries (best grades first)?',0,0,2,'CD3F8B54-CB08-4D82-A4F5-16477BB15BD2','fda8e54c-5755-4ad4-86a1-b77698bbd5a0',1,0,'2026-04-08 13:43:56.227422','2026-04-10 08:28:52.880375'),('0A632C39-3ACA-4F66-A3E6-D80831E779E0','Which query calculates the average grade specifically for students whose last name is either \'Boukezane\' or \'Eli\'?',1,3,3,'45D6C72F-A6A7-46C5-857C-E199CDFE978D','fda8e54c-5755-4ad4-86a1-b77698bbd5a0',1,0,'2026-04-10 08:17:28.374991','2026-04-10 08:33:12.908211'),('189D2927-6365-4246-B9FD-A72F9737A4CE','Which of the following SQL queries will successfully retrieve the names of students who scored more than 60, assuming \'Grade\' is the numeric column containing the score?',0,0,2,'CD3F8B54-CB08-4D82-A4F5-16477BB15BD2','fda8e54c-5755-4ad4-86a1-b77698bbd5a0',1,0,'2026-04-08 13:43:56.050472','2026-04-10 08:28:54.988870'),('39AD5FA5-41BF-437A-B4C4-A06AF180FD27','Which query counts the total number of records in the Sheet1 table?',1,3,0,'45D6C72F-A6A7-46C5-857C-E199CDFE978D','fda8e54c-5755-4ad4-86a1-b77698bbd5a0',1,1,'2026-04-08 13:55:26.964157',NULL),('3A302A81-64AD-4096-A4AB-82A46D4D9EBD','If you needed to retrieve the full names (First Name, Last Name) and the average grade for students who have scored above 60, which combination of clauses is required?',0,3,0,'45D6C72F-A6A7-46C5-857C-E199CDFE978D','fda8e54c-5755-4ad4-86a1-b77698bbd5a0',1,1,'2026-04-10 08:38:42.887280',NULL),('565BB388-A6FB-405C-A2F6-54D784520E85','fdehgwertyh',1,2,1,'45D6C72F-A6A7-46C5-857C-E199CDFE978D','fda8e54c-5755-4ad4-86a1-b